%[text] #### Experiment 1
load("lab3_exp1_data.mat")

% Plot with currents as a function of base voltage
figure() %[output:767a1598]
yscale("log") %[output:767a1598]
hold on; %[output:767a1598]
yyaxis left %[output:767a1598]
semilogy(Vb, Ib, '.', DisplayName='Measured') %[output:767a1598]
ylabel('Base Current (A)') %[output:767a1598]
yyaxis right %[output:767a1598]
yscale("log") %[output:767a1598]
semilogy(Vb, Iout, '.', DisplayName='Measured') %[output:767a1598]
ylabel('Collector Current (A)') %[output:767a1598]
xlabel('Base Voltage (V)') %[output:767a1598]
title('Bipolar Transistor Current Characteristics') %[output:767a1598]

yyaxis left %[output:767a1598]
vals_range = find(Vb > 0.5);
plot_range = linspace(0.3,0.7, 101);
[~, ~, m, b, ~] = linefit(Vb(vals_range), log(Ib(vals_range)), 1e-4);
plot(plot_range, exp(m .* plot_range + b), DisplayName=['Fit: y = e^{', num2str(m), ' ', char(8487), ' x + ', num2str(b), ' A}']) %[output:767a1598]

yyaxis right %[output:767a1598]
vals_range = find(Vb > 0.37);
plot_range = linspace(0.3,0.7, 101);
[~, ~, m, b, ~] = linefit(Vb(vals_range), log(Iout(vals_range)), 1e-4);
plot(plot_range, exp(m .* plot_range + b), DisplayName=['Fit: y = e^{', num2str(m), ' ', char(8487), ' x + ', num2str(b), ' A}']) %[output:767a1598]

legend(Location='southoutside') %[output:767a1598]

% Current Gain Plot
current_gain = Iout ./ Ib;

figure() %[output:95674674]
semilogx(Ib, current_gain, '.', DisplayName='Measured') %[output:95674674]
hold on; %[output:95674674]
vals_range = find(Ib > 1e-10);
plot_range = logspace(-10, -5, 101);
% fit_vals = fit(log(Ib(vals_range))', log(current_gain(vals_range))', "exp(a * x + b)");
% plot(plot_range, exp(fit_vals(1) .* plot_range + fit_vals(2)), DisplayName='Theoretical Fit')

xlabel('Base Current (A)') %[output:95674674]
ylabel('Current Gain, \beta (Unitless)') %[output:95674674]
title('Bipolar Transistor Current Gain Characteristics') %[output:95674674]
legend(Location='southoutside') %[output:95674674]
axis([1e-10, 1e-4, 0, 500]) %[output:3fab9253] %[output:95674674]

% r_b vs I_b
incremental_resistance = diff(Vb) ./ diff(Ib);

figure() %[output:650474eb]
loglog(Ib(1:end-1), incremental_resistance, '.', DisplayName='Measured') %[output:650474eb]
hold on; %[output:650474eb]
plot(logspace(-10, -5, 101), 0.025 ./ logspace(-10, -5, 101), DisplayName='Theoretical Fit') %[output:650474eb]

xlabel('Base Current (A)') %[output:650474eb]
ylabel('Incremental Resistance, r_{b} (\Omega)') %[output:650474eb]
title('Bipolar Transistor Incremental Resistance Characteristics') %[output:650474eb]
legend(Location='southoutside') %[output:650474eb]

% g_m vs I_c
incremental_transconductance_gain = diff(Iout) ./ diff(Vb);

figure() %[output:6c6d95c2]
loglog(Iout(1:end-1), incremental_transconductance_gain, '.', DisplayName='Measured') %[output:6c6d95c2]
hold on; %[output:6c6d95c2]
plot(logspace(-10, -2, 101), logspace(-10, -2, 101) ./ 0.025, DisplayName='Theoretical Fit') %[output:6c6d95c2]

xlabel('Collector Current (A)') %[output:6c6d95c2]
ylabel(['Incremental Transconductance Gain, g_{m} (', char(8487), ')']) %[output:6c6d95c2]
title('Bipolar Transistor Incremental Transconductance Characteristics') %[output:6c6d95c2]
legend(Location='southoutside') %[output:6c6d95c2]
%%
%[text] #### Experiment 4
load("lab3_exp3_data.mat") %[output:65031ef3] %[output:0bd19ab1] %[output:6257bb41] %[output:784544ae] %[output:7df7c8b0]
load("lab3_exp4_data.mat")

% Voltage Transfer Characteristic Plot + Experiment 3 Plot
figure() %[output:717e5d9e]
hold on; %[output:717e5d9e]
plot(Vin10k_e4, Vout10k_e4, '.', DisplayName='mR = 10 k\Omega; R = 1 k\Omega') %[output:717e5d9e]
plot(Vin5k_e4, Vout5k_e4, '.', DisplayName='mR = 5 k\Omega; R = 1 k\Omega') %[output:717e5d9e]
plot(Vin2k_e4, Vout2k_e4, '.', DisplayName='mR = 2 k\Omega; R = 1 k\Omega') %[output:717e5d9e]
plot(Vin_e3, Vout_e3, '.', DisplayName='mR = 0 \Omega; R = 1 k\Omega (Common Collector Amplifier)') %[output:717e5d9e]

fit_vals = polyfit(Vin_e3(find(Vout_e3 > 0.75)), Vout_e3(find(Vout_e3 > 0.75)), 1);
plot(linspace(0, 5, 101), fit_vals(1) .* linspace(0, 5, 101) + fit_vals(2), DisplayName=['Common Collector Amplifier Behavior Fit: y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:717e5d9e]

vals_range = find(Vin10k_e4 > 0.5 & Vin10k_e4 < 1.15);
plot_range = linspace(0.5, 1.25, 101);
fit_vals = polyfit(Vin10k_e4(vals_range), Vout10k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 10 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:717e5d9e]

vals_range = find(Vin5k_e4 > 0.5 & Vin5k_e4 < 1.5);
plot_range = linspace(0.5, 1.75, 101);
fit_vals = polyfit(Vin5k_e4(vals_range), Vout5k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 5 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:717e5d9e]

vals_range = find(Vin2k_e4 > 0.5 & Vin2k_e4 < 2.2);
plot_range = linspace(0.5, 3, 101);
fit_vals = polyfit(Vin2k_e4(vals_range), Vout2k_e4(vals_range), 1);
plot(plot_range, fit_vals(1) .* plot_range + fit_vals(2), DisplayName=['Inverting Amplifier Behavior Fit (mR = 2 k\Omega): y = ', num2str(fit_vals(1), 3), 'x + ', num2str(fit_vals(2), 3), ' V']) %[output:717e5d9e]

title('Common-Emitter Amplifier Voltage Transfer Characteristics') %[output:717e5d9e]
xlabel('Input Voltage (V)') %[output:717e5d9e]
ylabel('Output Voltage (V)') %[output:717e5d9e]
legend(Location="southoutside") %[output:717e5d9e] %[output:0ea912d9]

